import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
WIDTH = GRID_WIDTH * CELL_SIZE
HEIGHT = GRID_HEIGHT * CELL_SIZE
MARGIN = 5
PLAYER_WIDTH = WIDTH // 3 - MARGIN * 2
PLAYER_HEIGHT = HEIGHT
COLORS = [(0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
          (255, 255, 0), (255, 0, 255), (0, 255, 255), (255, 255, 255)]
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
    [[0, 1, 0], [1, 1, 1]]   # T
]

class Player:
    def __init__(self, player_id, x_offset):
        self.id = player_id
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.score = 0
        self.x_offset = x_offset
        self.current_piece = None
        self.current_x = 0
        self.current_y = 0
        self.game_over = False
        self.lines_cleared = 0

    def new_piece(self):
        self.current_piece = random.choice(SHAPES)
        self.current_x = GRID_WIDTH // 2 - len(self.current_piece[0]) // 2
        self.current_y = 0
        if not self.is_valid_position(self.current_piece, self.current_x, self.current_y):
            self.game_over = True

    def is_valid_position(self, piece, x, y):
        for i in range(len(piece)):
            for j in range(len(piece[0])):
                if piece[i][j] == 1:
                    grid_x = x + j
                    grid_y = y + i
                    if grid_x < 0 or grid_x >= GRID_WIDTH or grid_y >= GRID_HEIGHT or self.grid[grid_y][grid_x] != 0:
                        return False
        return True

    def rotate_piece(self):
        if self.current_piece is None:
            return
        rotated_piece = list(zip(*self.current_piece[::-1]))
        if self.is_valid_position(rotated_piece, self.current_x, self.current_y):
            self.current_piece = rotated_piece

    def move(self, dx):
        if self.current_piece is None:
            return
        new_x = self.current_x + dx
        if self.is_valid_position(self.current_piece, new_x, self.current_y):
            self.current_x = new_x

    def drop(self):
        if self.current_piece is None:
            return
        new_y = self.current_y + 1
        if self.is_valid_position(self.current_piece, self.current_x, new_y):
            self.current_y = new_y
        else:
            self.lock_piece()

    def lock_piece(self):
        if self.current_piece is None:
            return
        for i in range(len(self.current_piece)):
            for j in range(len(self.current_piece[0])):
                if self.current_piece[i][j] == 1:
                    self.grid[self.current_y + i][self.current_x + j] = self.id + 1
        self.current_piece = None
        self.clear_lines()
        self.new_piece()

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        if lines_cleared > 0:
            self.score += lines_cleared ** 2 * 100
            self.lines_cleared += lines_cleared

    def draw(self, screen):
        # Draw grid
        for i in range(GRID_HEIGHT):
            for j in range(GRID_WIDTH):
                color = COLORS[self.grid[i][j]]
                pygame.draw.rect(screen, color,
                                 (self.x_offset + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(screen, (50, 50, 50),
                                 (self.x_offset + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

        # Draw current piece
        if self.current_piece:
            for i in range(len(self.current_piece)):
                for j in range(len(self.current_piece[0])):
                    if self.current_piece[i][j] == 1:
                        pygame.draw.rect(screen, COLORS[self.id + 1],
                                         (self.x_offset + (self.current_x + j) * CELL_SIZE, (self.current_y + i) * CELL_SIZE,
                                          CELL_SIZE, CELL_SIZE))
                        pygame.draw.rect(screen, (50, 50, 50),
                                         (self.x_offset + (self.current_x + j) * CELL_SIZE, (self.current_y + i) * CELL_SIZE,
                                          CELL_SIZE, CELL_SIZE), 1)

        # Display score
        font = pygame.font.Font(None, 36)
        text = font.render(f"Player {self.id + 1}: {self.score}", True, (255, 255, 255))
        screen.blit(text, (self.x_offset, HEIGHT + 10))

        # Display lines cleared
        text = font.render(f"Lines: {self.lines_cleared}", True, (255, 255, 255))
        screen.blit(text, (self.x_offset, HEIGHT + 50))

        if self.game_over:
            text = font.render("Game Over", True, (255, 0, 0))
            text_rect = text.get_rect(center=(self.x_offset + PLAYER_WIDTH // 2, HEIGHT // 2))
            screen.blit(text, text_rect)

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH * 3 + MARGIN * 6, HEIGHT + 100))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [
            Player(0, MARGIN),
            Player(1, WIDTH + MARGIN * 3),
            Player(2, WIDTH * 2 + MARGIN * 5)
        ]
        self.game_over = False
        self.frame_count = 0
        self.drop_speed = 30  # Drop every 30 frames
        self.font = pygame.font.Font(None, 36)

        for player in self.players:
            player.new_piece()

    def handle_input(self, event):
        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_a:
                self.players[0].move(-1)
            elif event.key == pygame.K_d:
                self.players[0].move(1)
            elif event.key == pygame.K_w:
                self.players[0].rotate_piece()
            elif event.key == pygame.K_s:
                self.players[0].drop()

            if event.key == pygame.K_j:
                self.players[1].move(-1)
            elif event.key == pygame.K_l:
                self.players[1].move(1)
            elif event.key == pygame.K_i:
                self.players[1].rotate_piece()
            elif event.key == pygame.K_k:
                self.players[1].drop()

            if event.key == pygame.K_LEFT:
                self.players[2].move(-1)
            elif event.key == pygame.K_RIGHT:
                self.players[2].move(1)
            elif event.key == pygame.K_UP:
                self.players[2].rotate_piece()
            elif event.key == pygame.K_DOWN:
                self.players[2].drop()

    def update(self):
        if self.game_over:
            return

        self.frame_count += 1
        for player in self.players:
            if not player.game_over:
                if self.frame_count % self.drop_speed == 0:
                    player.drop()
                if player.game_over:
                    self.game_over = all(p.game_over for p in self.players)

    def render(self):
        self.screen.fill((0, 0, 0))
        for player in self.players:
            player.draw(self.screen)

        # Display overall score
        total_score = sum(player.score for player in self.players)
        text = self.font.render(f"Total Score: {total_score}", True, (255, 255, 255))
        self.screen.blit(text, (WIDTH * 3 // 2 - text.get_width() // 2, HEIGHT + 10))

        pygame.display.flip()

    def run(self):
        running = True
        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                self.handle_input(event)

            self.update()
            self.render()
            self.clock.tick(30)

        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
WIDTH = GRID_WIDTH * CELL_SIZE
HEIGHT = GRID_HEIGHT * CELL_SIZE
MARGIN = 50
TOTAL_WIDTH = WIDTH + 2 * MARGIN
TOTAL_HEIGHT = HEIGHT + 2 * MARGIN
FPS = 30

# Colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
ORANGE = (255, 165, 0)

COLORS = [GRAY, RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA, ORANGE]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[0, 1, 0], [1, 1, 1]],  # T
]


class Tetromino:
    def __init__(self, x, y, shape_index):
        self.x = x
        self.y = y
        self.shape = SHAPES[shape_index]
        self.color = COLORS[shape_index + 1]
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])

        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_width(self):
        return len(self.shape[0])

    def get_height(self):
        return len(self.shape)

    def get_cells(self):
        cells = []
        for row in range(self.get_height()):
            for col in range(self.get_width()):
                if self.shape[row][col]:
                    cells.append((self.x + col, self.y + row))
        return cells


class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        for x, y in tetromino.get_cells():
            if x < 0 or x >= self.width or y >= self.height:
                return False
            if y >= 0 and self.grid[y][x] != 0:
                return False
        return True

    def place_tetromino(self, tetromino):
        for x, y in tetromino.get_cells():
            if y >= 0:
                self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0])


class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.score = 0
        self.lines_cleared = 0
        self.contribution = 0.0

    def update_score(self, lines_cleared):
        self.lines_cleared += lines_cleared
        if lines_cleared == 1:
            self.score += 40
        elif lines_cleared == 2:
            self.score += 100
        elif lines_cleared == 3:
            self.score += 300
        elif lines_cleared == 4:
            self.score += 1200

    def reset_contribution(self):
        self.contribution = 0.0

    def calculate_contribution(self, total_lines_cleared):
        if total_lines_cleared > 0:
            self.contribution = self.lines_cleared / total_lines_cleared
        else:
            self.contribution = 0.0


class TetrisGame:
    def __init__(self, num_players=3):
        pygame.init()
        self.screen = pygame.display.set_mode((TOTAL_WIDTH, TOTAL_HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.players = [Player(i + 1) for i in range(num_players)]
        self.current_tetromino = self.new_tetromino()
        self.next_tetromino = self.new_tetromino()
        self.game_over = False
        self.drop_speed = 1
        self.frame_count = 0
        self.total_lines_cleared = 0
        self.font = pygame.font.Font(None, 30)
        self.current_player_index = 0
        self.player_colors = [RED, GREEN, BLUE]  # Assign colors to players
        self.player_controls = {
            1: {'left': pygame.K_a, 'right': pygame.K_d, 'rotate': pygame.K_s, 'down': pygame.K_w},
            2: {'left': pygame.K_j, 'right': pygame.K_l, 'rotate': pygame.K_k, 'down': pygame.K_i},
            3: {'left': pygame.K_LEFT, 'right': pygame.K_RIGHT, 'rotate': pygame.K_UP, 'down': pygame.K_DOWN}
        }

    def new_tetromino(self):
        shape_index = random.randint(0, len(SHAPES) - 1)
        return Tetromino(GRID_WIDTH // 2 - 2, 0, shape_index)

    def drop(self):
        self.current_tetromino.y += 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.y -= 1
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            self.total_lines_cleared += lines_cleared
            self.players[self.current_player_index].update_score(lines_cleared)
            self.current_tetromino = self.next_tetromino
            self.next_tetromino = self.new_tetromino()
            self.current_player_index = (self.current_player_index + 1) % len(self.players)
            if self.grid.is_game_over():
                self.game_over = True
            return True
        return False

    def handle_input(self):
        player_controls = self.player_controls[self.current_player_index + 1]
        keys = pygame.key.get_pressed()

        if keys[player_controls['left']]:
            self.current_tetromino.x -= 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x += 1
        if keys[player_controls['right']]:
            self.current_tetromino.x += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x -= 1
        if keys[player_controls['rotate']]:
            original_shape = self.current_tetromino.shape
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.shape = original_shape
        if keys[player_controls['down']]:
            self.drop()

    def draw_grid(self):
        for y in range(self.grid.height):
            for x in range(self.grid.width):
                color = self.grid.grid[y][x]
                if color:
                    pygame.draw.rect(self.screen, color,
                                     (MARGIN + x * CELL_SIZE, MARGIN + y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                else:
                    pygame.draw.rect(self.screen, GRAY,
                                     (MARGIN + x * CELL_SIZE, MARGIN + y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_tetromino(self, tetromino):
        for x, y in tetromino.get_cells():
            if y >= 0:
                pygame.draw.rect(self.screen, tetromino.color,
                                 (MARGIN + x * CELL_SIZE, MARGIN + y * CELL_SIZE, CELL_SIZE, CELL_SIZE))

    def draw_next_tetromino(self):
        text = self.font.render("Next:", True, WHITE)
        self.screen.blit(text, (WIDTH + MARGIN + 10, MARGIN))
        for x, y in self.next_tetromino.get_cells():
            pygame.draw.rect(self.screen, self.next_tetromino.color,
                             (WIDTH + MARGIN + 10 + (x - self.next_tetromino.x) * CELL_SIZE,
                              MARGIN + 30 + (y - self.next_tetromino.y) * CELL_SIZE, CELL_SIZE, CELL_SIZE))

    def draw_scores(self):
        for i, player in enumerate(self.players):
            text = self.font.render(f"Player {player.player_id}: {player.score}", True, self.player_colors[i])
            self.screen.blit(text, (10, MARGIN + i * 30))

        current_player_text = self.font.render(f"Current Player: {self.current_player_index + 1}", True, self.player_colors[self.current_player_index])
        self.screen.blit(current_player_text, (10, TOTAL_HEIGHT - MARGIN))

    def draw_game_over(self):
        text = self.font.render("Game Over!", True, RED)
        text_rect = text.get_rect(center=(TOTAL_WIDTH // 2, TOTAL_HEIGHT // 2))
        self.screen.blit(text, text_rect)

        # Calculate contributions
        for player in self.players:
            player.calculate_contribution(self.total_lines_cleared)

        # Display contributions
        y_offset = text_rect.bottom + 20
        for i, player in enumerate(self.players):
            contribution_text = self.font.render(f"Player {player.player_id} Contribution: {player.contribution:.2f}", True, self.player_colors[i])
            contribution_rect = contribution_text.get_rect(center=(TOTAL_WIDTH // 2, y_offset))
            self.screen.blit(contribution_text, contribution_rect)
            y_offset += 30

    def run(self):
        running = True
        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False

            if not self.game_over:
                self.handle_input()
                self.frame_count += 1
                if self.frame_count >= FPS // self.drop_speed:
                    self.frame_count = 0
                    self.drop()

                self.screen.fill(BLACK)
                self.draw_grid()
                self.draw_tetromino(self.current_tetromino)
                self.draw_next_tetromino()
                self.draw_scores()
            else:
                self.screen.fill(BLACK)
                self.draw_game_over()

            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.quit()


if __name__ == "__main__":
    game = TetrisGame()
