                if event.key == pygame.K_PERIOD:
                    self.players[2].drop_piece()

    def update(self):
        if not self.game_over:
            for player in self.players:
                if self.frame_count % (FPS // 2) == 0:
                    if not player.move_piece_down():
                        player.place_piece()
                        if player.is_game_over():
                            self.game_over = True
                            break
            self.frame_count += 1

    def render(self):
        self.screen.fill(COLORS[0])  # Black background

        for i, player in enumerate(self.players):
            grid = player.get_grid()
            piece = player.get_piece()
            next_piece = player.get_next_piece()
            offset = i * GRID_WIDTH * BLOCK_SIZE

            # Draw Grid
            for row_index, row in enumerate(grid):
                for col_index, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(self.screen, COLORS[cell],
                                         (col_index * BLOCK_SIZE + offset, row_index * BLOCK_SIZE,
                                          BLOCK_SIZE, BLOCK_SIZE))
                    else:
                        pygame.draw.rect(self.screen, COLORS[0],
                                         (col_index * BLOCK_SIZE + offset, row_index * BLOCK_SIZE,
                                          BLOCK_SIZE, BLOCK_SIZE), 1) #Outline

            # Draw Piece
            piece_shape = piece.get_shape()
            piece_color = piece.get_color()
            piece_x = piece.get_x()
            piece_y = piece.get_y()

            for row_index, row in enumerate(piece_shape):
                for col_index, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(self.screen, COLORS[piece_color],
                                         ((piece_x + col_index) * BLOCK_SIZE + offset, (piece_y + row_index) * BLOCK_SIZE,
                                          BLOCK_SIZE, BLOCK_SIZE))

            # Draw Next Piece
            next_piece_shape = next_piece.get_shape()
            next_piece_color = next_piece.get_color()
            next_piece_x = GRID_WIDTH // 2 - len(next_piece_shape[0]) // 2
            next_piece_y = GRID_HEIGHT - 4

            for row_index, row in enumerate(next_piece_shape):
                for col_index, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(self.screen, COLORS[next_piece_color],
                                         ((next_piece_x + col_index) * BLOCK_SIZE + offset, (next_piece_y + row_index) * BLOCK_SIZE,
                                          BLOCK_SIZE, BLOCK_SIZE))

            # Display Score
            score_text = self.font.render(f"Score: {player.get_score()}", True, COLORS[7])
            self.screen.blit(score_text, (offset, 20))

        if self.game_over:
            total_score = sum(player.get_score() for player in self.players)
            contributions = [player.get_contribution() for player in self.players]
            total_contribution = sum(contributions)
            if total_contribution == 0:
                percentages = [1/len(self.players) * 100 for _ in self.players]
            else:
                percentages = [contribution / total_contribution * 100 for contribution in contributions]

            game_over_text = self.font.render(f"Game Over! Total Score: {total_score}", True, COLORS[7])
            self.screen.blit(game_over_text, (SCREEN_WIDTH // 2 - game_over_text.get_width() // 2, SCREEN_HEIGHT // 2 - 50))

            for i, player in enumerate(self.players):
                contribution_text = self.font.render(f"Player {i+1}: {percentages[i]:.2f}%", True, COLORS[7])
                offset = i * GRID_WIDTH * BLOCK_SIZE
                self.screen.blit(contribution_text, (offset, SCREEN_HEIGHT // 2))

        pygame.display.flip()

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()
            self.render()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
WIDTH = GRID_WIDTH * BLOCK_SIZE * 3  # Three players
HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
COLORS = [
    (0, 0, 0),       # Black (Empty)
    (255, 0, 0),     # Red
    (0, 255, 0),     # Green
    (0, 0, 255),     # Blue
    (255, 255, 0),   # Yellow
    (255, 0, 255),   # Magenta
    (0, 255, 255),   # Cyan
    (255, 255, 255)    # White
]

SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]]   # T
]

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, shape, x, y):
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    grid_x = x + j
                    grid_y = y + i
                    if (grid_x < 0 or grid_x >= self.width or
                        grid_y < 0 or grid_y >= self.height or
                        self.grid[grid_y][grid_x] != 0):
                        return False
        return True

    def place_shape(self, shape, x, y, color):
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    self.grid[y + i][x + j] = color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0])

    def draw(self, screen, offset_x):
        for y in range(self.height):
            for x in range(self.width):
                color = COLORS[self.grid[y][x]]
                pygame.draw.rect(screen, color,
                                 (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE,
                                  BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(screen, (128, 128, 128),
                                 (offset_x + x * BLOCK_SIZE, y * BLOCK_SIZE,
                                  BLOCK_SIZE, BLOCK_SIZE), 1)  # Grid lines


class Piece:
    def __init__(self, shape=None, x=0, y=0, color=0):
        if shape is None:
            self.shape = random.choice(SHAPES)
        else:
            self.shape = shape
        self.x = x
        self.y = y
        self.color = color if color else random.randint(1, len(COLORS) - 1)

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = [list(row) for row in rotated_shape]

class Player:
    def __init__(self, player_id, grid_width, grid_height):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.score = 0
        self.current_piece = None
        self.next_piece = Piece()
        self.game_over = False
        self.lines_cleared = 0
        self.contribution = 0

    def new_piece(self):
        self.current_piece = self.next_piece
        self.current_piece.x = self.grid.width // 2 - len(self.current_piece.shape[0]) // 2
        self.current_piece.y = 0
        self.next_piece = Piece()
        if not self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x, self.current_piece.y):
            self.game_over = True

    def move_piece(self, dx):
        if not self.game_over:
            new_x = self.current_piece.x + dx
            if self.grid.is_valid_move(self.current_piece.shape, new_x, self.current_piece.y):
                self.current_piece.x = new_x

    def drop_piece(self):
        if not self.game_over:
            new_y = self.current_piece.y + 1
            if self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x, new_y):
                self.current_piece.y = new_y
                return False
            else:
                self.grid.place_shape(self.current_piece.shape, self.current_piece.x, self.current_piece.y, self.current_piece.color)
                lines_cleared = self.grid.clear_lines()
                self.lines_cleared += lines_cleared
                self.score += lines_cleared ** 2 * 100
                self.new_piece()
                return True

    def rotate_piece(self):
        if not self.game_over:
            original_shape = [list(row) for row in self.current_piece.shape]
            self.current_piece.rotate()
            if not self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x, self.current_piece.y):
                self.current_piece.shape = original_shape

    def update_contribution(self, total_score):
        if total_score > 0:
            self.contribution = self.score / total_score
        else:
            self.contribution = 0

    def draw_next_piece(self, screen, offset_x, offset_y):
        font = pygame.font.Font(None, 24)
        text = font.render(f"Next Piece:", True, (255, 255, 255))
        screen.blit(text, (offset_x, offset_y))

        shape = self.next_piece.shape
        color = COLORS[self.next_piece.color]

        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, color,
                                     (offset_x + j * BLOCK_SIZE, offset_y + (i+2) * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, (128, 128, 128),
                                     (offset_x + j * BLOCK_SIZE, offset_y + (i+2) * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_text(screen, text, x, y, color=(255, 255, 255), font_size=30):
    font = pygame.font.Font(None, font_size)
    text_surface = font.render(text, True, color)
    text_rect = text_surface.get_rect(center=(x, y))
    screen.blit(text_surface, text_rect)

def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Collaborative Tetris")

    players = [Player(i + 1, GRID_WIDTH, GRID_HEIGHT) for i in range(3)]
    for player in players:
        player.new_piece()

    clock = pygame.time.Clock()
    fall_speed = 1  # Blocks per second
    fall_interval = 1 / fall_speed
    last_fall_time = pygame.time.get_ticks()

    running = True
    while running:
        screen.fill((0, 0, 0))

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    players[0].move_piece(-1)
                if event.key == pygame.K_RIGHT:
                    players[0].move_piece(1)
                if event.key == pygame.K_DOWN:
                    players[0].drop_piece()
                if event.key == pygame.K_UP:
                    players[0].rotate_piece()

                if event.key == pygame.K_a:
                    players[1].move_piece(-1)
                if event.key == pygame.K_d:
                    players[1].move_piece(1)
                if event.key == pygame.K_s:
                    players[1].drop_piece()
                if event.key == pygame.K_w:
                    players[1].rotate_piece()

                if event.key == pygame.K_j:
                    players[2].move_piece(-1)
                if event.key == pygame.K_l:
                    players[2].move_piece(1)
                if event.key == pygame.K_k:
                    players[2].drop_piece()
                if event.key == pygame.K_i:
                    players[2].rotate_piece()

        # Automatic piece falling
        current_time = pygame.time.get_ticks()
        for player in players:
            if not player.game_over:
                if current_time - last_fall_time > fall_interval * 1000:
                    if player.current_piece:
                        player.drop_piece()

        last_fall_time = current_time

        # Draw grids and pieces
        for i, player in enumerate(players):
            offset_x = i * GRID_WIDTH * BLOCK_SIZE
            player.grid.draw(screen, offset_x)

            if player.current_piece:
                for row_index, row in enumerate(player.current_piece.shape):
                    for col_index, cell in enumerate(row):
                        if cell:
                            x = offset_x + (player.current_piece.x + col_index) * BLOCK_SIZE
                            y = (player.current_piece.y + row_index) * BLOCK_SIZE
                            pygame.draw.rect(screen, COLORS[player.current_piece.color], (x, y, BLOCK_SIZE, BLOCK_SIZE))
                            pygame.draw.rect(screen, (128, 128, 128), (x, y, BLOCK_SIZE, BLOCK_SIZE), 1)

            # Draw scores
            draw_text(screen, f"Player {player.player_id}: {player.score}", offset_x + GRID_WIDTH * BLOCK_SIZE // 2, 20, font_size=20)
            player.draw_next_piece(screen, offset_x, HEIGHT - 150)

            if player.game_over:
                draw_text(screen, "Game Over", offset_x + GRID_WIDTH * BLOCK_SIZE // 2, HEIGHT // 2, color=(255, 0, 0))

        # Calculate total score and contributions
        total_score = sum(player.score for player in players)
        for player in players:
            player.update_contribution(total_score)

        # Display contributions
        y_offset = 50
        for player in players:
            draw_text(screen, f"Player {player.player_id} Contribution: {player.contribution:.2f}", WIDTH // 2, y_offset, font_size=20)
            y_offset += 25

        all_game_over = all(player.game_over for player in players)
        if all_game_over:
            draw_text(screen, "All Games Over!", WIDTH // 2, HEIGHT // 2, color=(255, 0, 0), font_size=40)

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()

if __name__ == "__main__":
    main()

