import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * BLOCK_SIZE * 3  # Triple width for 3 players
SCREEN_HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30
COLORS = [(0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
          (255, 255, 0), (255, 0, 255), (0, 255, 255), (255, 255, 255)]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]]   # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j] == 1:
                    cells.append((self.x + j, self.y + i))
        return cells

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        for x, y in tetromino.get_cells():
            if x < 0 or x >= self.width or y >= self.height:
                return False
            if y >= 0 and self.grid[y][x] != 0:
                return False
        return True

    def place_tetromino(self, tetromino):
        for x, y in tetromino.get_cells():
            if y >= 0:
                self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y][x] != 0 for x in range(self.width)):
                lines_cleared += 1
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
        return lines_cleared

class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.grid_x_offset = grid_x_offset
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = random.randint(1, len(COLORS) - 1)
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def new_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.current_tetromino.x = GRID_WIDTH // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        if not self.grid.is_valid_move(self.current_tetromino):
            return False # Game Over
        return True

    def move_left(self):
        if self.current_tetromino:
            self.current_tetromino.x -= 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x += 1

    def move_right(self):
        if self.current_tetromino:
            self.current_tetromino.x += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x -= 1

    def move_down(self):
        if self.current_tetromino:
            self.current_tetromino.y += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.y -= 1
                self.grid.place_tetromino(self.current_tetromino)
                lines_cleared = self.grid.clear_lines()
                self.score += self.calculate_score(lines_cleared)
                return False # Tetromino landed
        return True # Tetromino still moving

    def rotate(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.shape
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.shape = original_shape # Revert rotation

    def calculate_score(self, lines_cleared):
        if lines_cleared == 1:
            return 40
        elif lines_cleared == 2:
            return 100
        elif lines_cleared == 3:
            return 300
        elif lines_cleared == 4:
            return 1200
        return 0

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [
            Player(1, 0),
            Player(2, GRID_WIDTH * BLOCK_SIZE),
            Player(3, GRID_WIDTH * BLOCK_SIZE * 2)
        ]
        self.game_over = [False, False, False]
        self.font = pygame.font.Font(None, 36)
        self.drop_delay = 500 # milliseconds
        self.last_drop_time = [pygame.time.get_ticks(), pygame.time.get_ticks(), pygame.time.get_ticks()] # one for each player
        self.player_controls = {
            1: {'left': pygame.K_a, 'right': pygame.K_d, 'down': pygame.K_s, 'rotate': pygame.K_w},
            2: {'left': pygame.K_j, 'right': pygame.K_l, 'down': pygame.K_k, 'rotate': pygame.K_i},
            3: {'left': pygame.K_LEFT, 'right': pygame.K_RIGHT, 'down': pygame.K_DOWN, 'rotate': pygame.K_UP}
        }

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
                pygame.quit()
                exit()

            if event.type == pygame.KEYDOWN:
                for i, player in enumerate(self.players):
                    if not self.game_over[i]:
                        if event.key == self.player_controls[player.player_id]['left']:
                            player.move_left()
                        elif event.key == self.player_controls[player.player_id]['right']:
                            player.move_right()
                        elif event.key == self.player_controls[player.player_id]['down']:
                            player.move_down()
                        elif event.key == self.player_controls[player.player_id]['rotate']:
                            player.rotate()

    def update(self):
        for i, player in enumerate(self.players):
            if not self.game_over[i]:
                current_time = pygame.time.get_ticks()
                if current_time - self.last_drop_time[i] > self.drop_delay:
                    self.last_drop_time[i] = current_time
                    if player.current_tetromino is None:
                        if not player.new_tetromino():
                            self.game_over[i] = True
                    else:
                        if not player.move_down():
                            player.current_tetromino = None
                            if not player.new_tetromino():
                                self.game_over[i] = True

    def render(self):
        self.screen.fill((0, 0, 0))

        for player in self.players:
            self.render_grid(player)
            self.render_score(player)
            self.render_next_tetromino(player)

        pygame.display.flip()

    def render_grid(self, player):
        for y in range(player.grid.height):
            for x in range(player.grid.width):
                color = COLORS[player.grid.grid[y][x]]
                pygame.draw.rect(self.screen, color,
                                 (player.grid_x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE,
                                  BLOCK_SIZE, BLOCK_SIZE))
                pygame.draw.rect(self.screen, (50, 50, 50),
                                 (player.grid_x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE,
                                  BLOCK_SIZE, BLOCK_SIZE), 1)

        if player.current_tetromino:
            for x, y in player.current_tetromino.get_cells():
                if y >= 0:
                    pygame.draw.rect(self.screen, COLORS[player.current_tetromino.color],
                                     (player.grid_x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(self.screen, (50, 50, 50),
                                     (player.grid_x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE), 1)

    def render_score(self, player):
        score_text = self.font.render(f"Player {player.player_id} Score: {player.score}", True, (255, 255, 255))
        self.screen.blit(score_text, (player.grid_x_offset, SCREEN_HEIGHT - 40))

    def render_next_tetromino(self, player):
        next_tetromino = player.next_tetromino
        text = self.font.render(f"Next:", True, (255, 255, 255))
        self.screen.blit(text, (player.grid_x_offset + GRID_WIDTH * BLOCK_SIZE + 10, 10))

        for i in range(len(next_tetromino.shape)):
            for j in range(len(next_tetromino.shape[0])):
                if next_tetromino.shape[i][j] == 1:
                    pygame.draw.rect(self.screen, COLORS[next_tetromino.color],
                                     (player.grid_x_offset + GRID_WIDTH * BLOCK_SIZE + 10 + j * BLOCK_SIZE,
                                      50 + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(self.screen, (50, 50, 50),
                                     (player.grid_x_offset + GRID_WIDTH * BLOCK_SIZE + 10 + j * BLOCK_SIZE,
                                      50 + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def run(self):
        self.running = True
        for player in self.players:
            player.new_tetromino()

        while self.running:
            self.handle_input()
            self.update()
            self.render()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

