        if total_contribution > 0:
            for player in self.players:
                player.score += (player.contribution / total_contribution) * self.shared_lines_cleared * 100
        else:
            for player in self.players:
                player.score += 0

        for player in self.players:
            player.reset_contribution()
        self.shared_lines_cleared = 0

    def draw_grid(self, player):
        player.grid.draw(self.screen, player.grid_offset)

    def draw_piece(self, player):
        shape = player.current_piece.shape
        color = COLORS[player.current_piece.color]
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    x = player.grid_offset + (player.current_piece.x + j) * CELL_SIZE
                    y = (player.current_piece.y + i) * CELL_SIZE
                    pygame.draw.rect(self.screen, color, (x, y, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(self.screen, (128, 128, 128), (x, y, CELL_SIZE, CELL_SIZE), 1)

    def draw_next_piece(self, player):
        shape = player.next_piece.shape
        color = COLORS[player.next_piece.color]
        text_surface = self.font.render(f"Next Piece (P{player.player_id}):", True, (255, 255, 255))
        self.screen.blit(text_surface, (player.grid_offset, SCREEN_HEIGHT - 150))

        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    x = player.grid_offset + j * CELL_SIZE
                    y = SCREEN_HEIGHT - 100 + i * CELL_SIZE
                    pygame.draw.rect(self.screen, color, (x, y, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(self.screen, (128, 128, 128), (x, y, CELL_SIZE, CELL_SIZE), 1)

    def draw_score(self, player):
        text_surface = self.font.render(f"Player {player.player_id} Score: {int(player.score)}", True, (255, 255, 255))
        self.screen.blit(text_surface, (player.grid_offset, 10))

    def run(self):
        while not self.game_over:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.game_over = True

            for player in self.players:
                self.handle_input(player)

            self.fall_counter += self.fall_speed
            if self.fall_counter >= FPS:
                self.fall_counter = 0
                for player in self.players:
                    self.drop_piece(player)
                self.update_scores()

            self.screen.fill((0, 0, 0))

            for player in self.players:
                self.draw_grid(player)
                self.draw_piece(player)
                self.draw_next_piece(player)
                self.draw_score(player)

            pygame.display.flip()
            self.clock.tick(FPS)

        print("Game Over!")
        for player in self.players:
            print(f"Player {player.player_id} Score: {int(player.score)}")
        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

