BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
COLORS = [
    (0, 255, 255),  # Cyan
    (0, 0, 255),    # Blue
    (255, 127, 0),  # Orange
    (255, 255, 0),  # Yellow
    (0, 255, 0),    # Green
    (255, 0, 0),    # Red
    (128, 0, 128)   # Purple
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 0], [1, 1, 1]]   # T
]


class Tetromino:
    def __init__(self, x, y, shape, color_index):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = COLORS[color_index]
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        for x in range(len(self.shape[0])):
            new_row = []
            for y in range(len(self.shape) - 1, -1, -1):
                new_row.append(self.shape[y][x])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i, row in enumerate(self.shape):
            for j, cell in enumerate(row):
                if cell:
                    cells.append((self.x + j, self.y + i))
        return cells


class Grid:
    def __init__(self, width, height, x_offset):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]
        self.x_offset = x_offset  # Offset for drawing the grid

    def is_valid_move(self, tetromino):
        for x, y in tetromino.get_cells():
            if x < 0 or x >= self.width or y >= self.height:
                return False
            if y >= 0 and self.grid[y][x] != 0:
                return False
        return True

    def place_tetromino(self, tetromino, color_index):
        for x, y in tetromino.get_cells():
            if y >= 0:  # Only place if within grid bounds
                self.grid[y][x] = color_index + 1  # +1 to avoid 0 (empty)

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x] != 0:
                    color = COLORS[self.grid[y][x] - 1]
                    pygame.draw.rect(screen, color,
                                     (self.x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, BLACK,
                                     (self.x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)
                else:
                    pygame.draw.rect(screen, GRAY,
                                     (self.x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)


class Player:
    def __init__(self, player_id, grid, controls):
        self.player_id = player_id
        self.grid = grid
        self.score = 0
        self.controls = controls  # Dictionary of controls
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.contribution = 0 # Track player's contribution to the score

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color_index = SHAPES.index(shape)
        return Tetromino(self.grid.width // 2 - len(shape[0]) // 2, -2, shape, color_index)

    def spawn_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        if not self.grid.is_valid_move(self.current_tetromino):
            return False  # Game over
        return True

    def move_left(self):
        self.current_tetromino.x -= 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.x += 1

    def move_right(self):
        self.current_tetromino.x += 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.x -= 1

    def move_down(self):
        self.current_tetromino.y += 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.y -= 1
            self.lock_tetromino()
            return False  # Tetromino locked
        return True

    def rotate(self):
        original_shape = self.current_tetromino.shape
        self.current_tetromino.rotate()
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.shape = original_shape  # Revert rotation

    def lock_tetromino(self):
        self.grid.place_tetromino(self.current_tetromino, SHAPES.index(self.current_tetromino.shape))
        lines_cleared = self.grid.clear_lines()
        if lines_cleared > 0:
            self.score += lines_cleared * lines_cleared * 100 # Example scoring
            self.contribution += lines_cleared * lines_cleared * 100

    def draw_tetromino(self, screen):
        if self.current_tetromino:
            for x, y in self.current_tetromino.get_cells():
                if y >= 0:
                    pygame.draw.rect(screen, self.current_tetromino.color,
                                     (self.grid.x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                    pygame.draw.rect(screen, BLACK,
                                     (self.grid.x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_next_tetromino(self, screen, x, y):
        for i, row in enumerate(self.next_tetromino.shape):
            for j, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, self.next_tetromino.color,
                                     (x + j * BLOCK_SIZE, y + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
