            Grid(grid_width, grid_height, 2 * grid_width * BLOCK_SIZE + 30)
        ]

        self.players = [
            Player(1, self.grids[0], {'left': pygame.K_a, 'right': pygame.K_d, 'down': pygame.K_s, 'rotate': pygame.K_w}),
            Player(2, self.grids[1], {'left': pygame.K_j, 'right': pygame.K_l, 'down': pygame.K_k, 'rotate': pygame.K_i}),
            Player(3, self.grids[2], {'left': pygame.K_LEFT, 'right': pygame.K_RIGHT, 'down': pygame.K_DOWN, 'rotate': pygame.K_UP})
        ]

        self.game_over = False
        self.fall_speed = 500  # Milliseconds
        self.last_fall_time = pygame.time.get_ticks()
        self.total_score = 0

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            if event.type == pygame.KEYDOWN:
                for player in self.players:
                    if event.key == player.controls['left']:
                        player.move_left()
                    if event.key == player.controls['right']:
                        player.move_right()
                    if event.key == player.controls['down']:
                        player.move_down()
                    if event.key == player.controls['rotate']:
                        player.rotate()

    def update(self):
        if self.game_over:
            return

        current_time = pygame.time.get_ticks()
        for player in self.players:
            if player.current_tetromino is None:
                if not player.spawn_tetromino():
                    self.game_over = True
                    return

            if current_time - self.last_fall_time > self.fall_speed:
                if not player.move_down():
                    # Tetromino locked, check for game over on next spawn
                    pass
                self.last_fall_time = current_time

        # Update total score based on player contributions
        self.total_score = sum(player.score for player in self.players)

    def render(self):
        self.screen.fill(BLACK)

        # Draw grids
        for grid in self.grids:
            grid.draw(self.screen)

        # Draw tetrominos
        for player in self.players:
            player.draw_tetromino(self.screen)

        # Draw next tetrominos
        for i, player in enumerate(self.players):
            player.draw_next_tetromino(self.screen, 10 + i * (GRID_WIDTH * BLOCK_SIZE + 10), SCREEN_HEIGHT - 5 * BLOCK_SIZE)

        # Draw scores
        for i, player in enumerate(self.players):
            score_text = self.font.render(f"P{player.player_id}: {player.score}", True, WHITE)
            self.screen.blit(score_text, (10 + i * (GRID_WIDTH * BLOCK_SIZE + 10), 10))

        # Draw total score
        total_score_text = self.font.render(f"Total Score: {self.total_score}", True, WHITE)
        self.screen.blit(total_score_text, (SCREEN_WIDTH // 2 - total_score_text.get_width() // 2, 10))

        if self.game_over:
            game_over_text = self.font.render("Game Over!", True, WHITE)
            self.screen.blit(game_over_text, (SCREEN_WIDTH // 2 - game_over_text.get_width() // 2, SCREEN_HEIGHT // 2))

        pygame.display.flip()

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()
            self.render()
            self.clock.tick(FPS)

        pygame.quit()


if __name__ == "__main__":
    game = Game()
    game.run()

