        self.color_index = color_index
        self.player_id = player_id

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = rotated_shape

    def move(self, dx, board):
        new_x = self.x + dx
        if not self.collides(new_x, self.y, board):
            self.x = new_x
            return True
        return False

    def move_down(self, board):
        new_y = self.y + 1
        if not self.collides(self.x, new_y, board):
            self.y = new_y
            return True
        return False

    def collides(self, x, y, board):
        for i, row in enumerate(self.shape):
            for j, cell in enumerate(row):
                if cell:
                    board_x = x + j
                    board_y = y + i
                    if (board_x < 0 or board_x >= GRID_WIDTH or board_y >= GRID_HEIGHT or
                            board[board_y][board_x] != 0):
                        return True
        return False

class Player:
    def __init__(self, player_id, x_offset):
        self.player_id = player_id
        self.board = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.score = 0
        self.x_offset = x_offset
        self.current_piece = None
        self.next_piece = self.create_piece()

    def create_piece(self):
        shape = random.choice(SHAPES)
        color_index = random.randint(1, len(COLORS) - 1)
        return Piece(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color_index, self.player_id)

    def new_piece(self):
        self.current_piece = self.next_piece
        self.next_piece = self.create_piece()
        if self.current_piece.collides(self.current_piece.x, self.current_piece.y, self.board):
            return False  # Game Over
        return True

    def drop_piece(self):
        while self.current_piece.move_down(self.board):
            pass
        self.lock_piece()

    def lock_piece(self):
        for i, row in enumerate(self.current_piece.shape):
            for j, cell in enumerate(row):
                if cell:
                    self.board[self.current_piece.y + i][self.current_piece.x + j] = self.current_piece.color_index
        self.clear_lines()

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.board[i]):
                del self.board[i]
                self.board.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        self.score += lines_cleared ** 2 * 100

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Cooperative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [
            Player(1, 0),
            Player(2, GRID_WIDTH * CELL_SIZE),
            Player(3, GRID_WIDTH * CELL_SIZE * 2)
        ]
        self.game_over = False
        self.fall_speed = 1  # Blocks fall one cell per frame
        self.fall_counter = 0
        self.player_contributions = {1: 0, 2: 0, 3: 0}
        self.total_score = 0

        for player in self.players:
            if not player.new_piece():
                self.game_over = True

    def handle_input(self, event):
        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_a:  # Player 1 Left
                self.players[0].current_piece.move(-1, self.players[0].board)
            elif event.key == pygame.K_d:  # Player 1 Right
                self.players[0].current_piece.move(1, self.players[0].board)
            elif event.key == pygame.K_s:  # Player 1 Down
                self.players[0].drop_piece()
                self.player_contributions[1] += 1
                if not self.players[0].new_piece():
                    self.game_over = True
            elif event.key == pygame.K_q:  # Player 1 Rotate
                self.players[0].current_piece.rotate()
                if self.players[0].current_piece.collides(self.players[0].current_piece.x, self.players[0].current_piece.y, self.players[0].board):
                    self.players[0].current_piece.rotate()
                    self.players[0].current_piece.rotate()
                    self.players[0].current_piece.rotate()

            elif event.key == pygame.K_j:  # Player 2 Left
                self.players[1].current_piece.move(-1, self.players[1].board)
            elif event.key == pygame.K_l:  # Player 2 Right
                self.players[1].current_piece.move(1, self.players[1].board)
            elif event.key == pygame.K_k:  # Player 2 Down
                self.players[1].drop_piece()
                self.player_contributions[2] += 1
                if not self.players[1].new_piece():
                    self.game_over = True
            elif event.key == pygame.K_i:  # Player 2 Rotate
                self.players[1].current_piece.rotate()
                if self.players[1].current_piece.collides(self.players[1].current_piece.x, self.players[1].current_piece.y, self.players[1].board):
                    self.players[1].current_piece.rotate()
                    self.players[1].current_piece.rotate()
                    self.players[1].current_piece.rotate()

            elif event.key == pygame.K_LEFT:  # Player 3 Left
                self.players[2].current_piece.move(-1, self.players[2].board)
            elif event.key == pygame.K_RIGHT:  # Player 3 Right
                self.players[2].current_piece.move(1, self.players[2].board)
            elif event.key == pygame.K_DOWN:  # Player 3 Down
                self.players[2].drop_piece()
                self.player_contributions[3] += 1
                if not self.players[2].new_piece():
                    self.game_over = True
            elif event.key == pygame.K_UP:  # Player 3 Rotate
                self.players[2].current_piece.rotate()
                if self.players[2].current_piece.collides(self.players[2].current_piece.x, self.players[2].current_piece.y, self.players[2].board):
                    self.players[2].current_piece.rotate()
                    self.players[2].current_piece.rotate()
                    self.players[2].current_piece.rotate()

    def update(self):
        if self.game_over:
            return

        self.fall_counter += 1
        if self.fall_counter >= FPS // self.fall_speed:
            self.fall_counter = 0
            for player in self.players:
                if player.current_piece:
                    if not player.current_piece.move_down(player.board):
                        player.lock_piece()
                        self.player_contributions[player.player_id] += 1
                        if not player.new_piece():
                            self.game_over = True
                            return

        self.total_score = sum(player.score for player in self.players)

    def render(self):
        self.screen.fill(COLORS[0])  # Black background

        for player in self.players:
            self.render_board(player)
            self.render_piece(player.current_piece, player.x_offset)
            self.render_next_piece(player)
            self.render_score(player)

        self.render_total_score()
        self.render_contributions()

        if self.game_over:
            self.render_game_over()

        pygame.display.flip()

    def render_board(self, player):
        for i in range(GRID_HEIGHT):
            for j in range(GRID_WIDTH):
                color_index = player.board[i][j]
                if color_index != 0:
                    pygame.draw.rect(self.screen, COLORS[color_index],
                                     (player.x_offset + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(self.screen, COLORS[7],
                                     (player.x_offset + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1) # White outline

    def render_piece(self, piece, x_offset):
        if piece:
            for i, row in enumerate(piece.shape):
                for j, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(self.screen, COLORS[piece.color_index],
                                         (x_offset + (piece.x + j) * CELL_SIZE, (piece.y + i) * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                        pygame.draw.rect(self.screen, COLORS[7],
                                         (x_offset + (piece.x + j) * CELL_SIZE, (piece.y + i) * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1) # White outline

    def render_next_piece(self, player):
        font = pygame.font.Font(None, 24)
        text = font.render(f"Next Piece (P{player.player_id}):", True, COLORS[7])
        self.screen.blit(text, (player.x_offset, SCREEN_HEIGHT - 100))

        next_piece = player.next_piece
        if next_piece:
            for i, row in enumerate(next_piece.shape):
                for j, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(self.screen, COLORS[next_piece.color_index],
                                         (player.x_offset + j * CELL_SIZE, SCREEN_HEIGHT - 70 + i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                        pygame.draw.rect(self.screen, COLORS[7],
                                         (player.x_offset + j * CELL_SIZE, SCREEN_HEIGHT - 70 + i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1) # White outline

    def render_score(self, player):
        font = pygame.font.Font(None, 36)
        text = font.render(f"P{player.player_id} Score: {player.score}", True, COLORS[7])
        self.screen.blit(text, (player.x_offset, 10))

    def render_total_score(self):
        font = pygame.font.Font(None, 48)
        text = font.render(f"Total Score: {self.total_score}", True, COLORS[7])
        text_rect = text.get_rect(center=(SCREEN_WIDTH // 2, 20))
        self.screen.blit(text, text_rect)

    def render_contributions(self):
        font = pygame.font.Font(None, 24)
        for i, player_id in enumerate(self.player_contributions):
            text = font.render(f"P{player_id} Contributions: {self.player_contributions[player_id]}", True, COLORS[7])
            self.screen.blit(text, (10, 50 + i * 30))

    def render_game_over(self):
        font = pygame.font.Font(None, 72)
        text = font.render("Game Over!", True, COLORS[1])
        text_rect = text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
        self.screen.blit(text, text_rect)

    def run(self):
        running = True
        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                self.handle_input(event)

            self.update()
            self.render()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
WIDTH = GRID_WIDTH * CELL_SIZE * 3  # Three players side-by-side
HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30
COLORS = [(0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
          (255, 255, 0), (255, 0, 255), (0, 255, 255), (255, 255, 255)]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 0], [1, 1, 1]]   # T
]

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, shape, offset_x, offset_y):
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    grid_x = offset_x + x
                    grid_y = offset_y + y
                    if (grid_x < 0 or grid_x >= self.width or
                        grid_y < 0 or grid_y >= self.height or
                        self.grid[grid_y][grid_x] != 0):
                        return False
        return True

    def place_shape(self, shape, offset_x, offset_y, color):
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[offset_y + y][offset_x + x] = color

    def clear_lines(self):
        lines_cleared = 0
        full_rows = [i for i, row in enumerate(self.grid) if all(row)]
        for row_index in full_rows:
            del self.grid[row_index]
            self.grid.insert(0, [0] * self.width)
            lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0])

    def render(self, screen, offset_x):
        for y, row in enumerate(self.grid):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, COLORS[cell],
                                     (offset_x + x * CELL_SIZE, y * CELL_SIZE,
                                      CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, COLORS[-1],
                                     (offset_x + x * CELL_SIZE, y * CELL_SIZE,
                                      CELL_SIZE, CELL_SIZE), 1)  # Grid lines

class Piece:
    def __init__(self, shape, color, grid_width):
        self.shape = shape
        self.color = color
        self.x = grid_width // 2 - len(shape[0]) // 2
        self.y = 0

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = [list(row) for row in rotated_shape]

class Player:
    def __init__(self, player_id, grid_width, grid_height):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.score = 0
        self.piece = None
        self.next_piece = self.create_piece(grid_width)
        self.lines_cleared = 0

    def create_piece(self, grid_width):
        shape = random.choice(SHAPES)
        color = random.randint(1, len(COLORS) - 2)
        return Piece(shape, color, grid_width)

    def new_piece(self, grid_width):
        self.piece = self.next_piece
        self.next_piece = self.create_piece(grid_width)
        self.piece.x = self.grid.width // 2 - len(self.piece.shape[0]) // 2
        self.piece.y = 0
        if not self.grid.is_valid_move(self.piece.shape, self.piece.x, self.piece.y):
            return True # Game Over
        return False

    def move_down(self):
        if self.grid.is_valid_move(self.piece.shape, self.piece.x, self.piece.y + 1):
            self.piece.y += 1
            return False
        else:
            self.grid.place_shape(self.piece.shape, self.piece.x, self.piece.y, self.piece.color)
            lines_cleared = self.grid.clear_lines()
            self.lines_cleared += lines_cleared
            self.score += lines_cleared ** 2 * 100
            return True

    def move_sideways(self, direction):
        new_x = self.piece.x + direction
        if self.grid.is_valid_move(self.piece.shape, new_x, self.piece.y):
            self.piece.x = new_x

    def rotate_piece(self):
        original_shape = [list(row) for row in self.piece.shape]
        self.piece.rotate()
        if not self.grid.is_valid_move(self.piece.shape, self.piece.x, self.piece.y):
            self.piece.shape = original_shape # Revert rotation

    def render(self, screen, offset_x):
        self.grid.render(screen, offset_x)
        if self.piece:
            for y, row in enumerate(self.piece.shape):
                for x, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(screen, COLORS[self.piece.color],
                                         (offset_x + (self.piece.x + x) * CELL_SIZE,
                                          (self.piece.y + y) * CELL_SIZE,
                                          CELL_SIZE, CELL_SIZE))
                        pygame.draw.rect(screen, COLORS[-1],
                                         (offset_x + (self.piece.x + x) * CELL_SIZE,
                                          (self.piece.y + y) * CELL_SIZE,
                                          CELL_SIZE, CELL_SIZE), 1)

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        pygame.display.set_caption("Cooperative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [Player(i, GRID_WIDTH, GRID_HEIGHT) for i in range(3)]
        self.game_over = [False] * 3
        self.font = pygame.font.Font(None, 36)
        self.frame_count = 0

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT and not self.game_over[0]:
                    self.players[0].move_sideways(-1)
                if event.key == pygame.K_RIGHT and not self.game_over[0]:
                    self.players[0].move_sideways(1)
                if event.key == pygame.K_DOWN and not self.game_over[0]:
                    self.players[0].move_down()
                if event.key == pygame.K_UP and not self.game_over[0]:
                    self.players[0].rotate_piece()

                if event.key == pygame.K_a and not self.game_over[1]:
                    self.players[1].move_sideways(-1)
                if event.key == pygame.K_d and not self.game_over[1]:
                    self.players[1].move_sideways(1)
                if event.key == pygame.K_s and not self.game_over[1]:
                    self.players[1].move_down()
                if event.key == pygame.K_w and not self.game_over[1]:
                    self.players[1].rotate_piece()

                if event.key == pygame.K_j and not self.game_over[2]:
                    self.players[2].move_sideways(-1)
                if event.key == pygame.K_l and not self.game_over[2]:
                    self.players[2].move_sideways(1)
                if event.key == pygame.K_k and not self.game_over[2]:
                    self.players[2].move_down()
                if event.key == pygame.K_i and not self.game_over[2]:
                    self.players[2].rotate_piece()

    def update(self):
        self.frame_count += 1
        for i, player in enumerate(self.players):
            if not self.game_over[i]:
                if not player.piece:
                    self.game_over[i] = player.new_piece(GRID_WIDTH)
                if self.frame_count % (FPS // 2) == 0: # Adjust speed
                    if player.move_down():
                        self.game_over[i] = player.new_piece(GRID_WIDTH)

    def render(self):
        self.screen.fill((0, 0, 0))
        for i, player in enumerate(self.players):
            player.render(self.screen, i * GRID_WIDTH * CELL_SIZE)
            score_text = self.font.render(f"Player {i+1}: {player.score}", True, COLORS[-1])
            self.screen.blit(score_text, (i * GRID_WIDTH * CELL_SIZE, HEIGHT - 30))
            if self.game_over[i]:
                game_over_text = self.font.render(f"Game Over", True, COLORS[1])
                text_rect = game_over_text.get_rect(center=(i * GRID_WIDTH * CELL_SIZE + GRID_WIDTH * CELL_SIZE // 2, HEIGHT // 2))
                self.screen.blit(game_over_text, text_rect)

        pygame.display.flip()

    def run(self):
        self.running = True
        while self.running:
            self.handle_input()
            self.update()
            self.render()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

