COLORS = [(0, 255, 255), (0, 0, 255), (255, 127, 0), (255, 255, 0), (0, 255, 0), (255, 0, 0), (128, 0, 128)]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 0], [1, 1, 1]]   # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])

        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j] == 1:
                    cells.append((self.x + j, self.y + i))
        return cells

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        for x, y in tetromino.get_cells():
            if x < 0 or x >= self.width or y >= self.height:
                return False
            if y >= 0 and self.grid[y][x] != 0:
                return False
        return True

    def place_tetromino(self, tetromino, color_index):
        for x, y in tetromino.get_cells():
            if y >= 0:
                self.grid[y][x] = color_index + 1 # +1 to avoid 0 (empty cell)

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen, offset):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x] != 0:
                    color = COLORS[self.grid[y][x] - 1]
                    pygame.draw.rect(screen, color, (offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, BLACK, (offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)
                else:
                    pygame.draw.rect(screen, WHITE, (offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, GRAY, (offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

class Player:
    def __init__(self, player_id, grid_width, grid_height, offset):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.score = 0
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.offset = offset
        self.contribution = 0 # Track player's contribution to the overall score

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color_index = random.randint(0, len(COLORS) - 1)
        return Tetromino(self.grid.width // 2 - len(shape[0]) // 2, 0, shape, COLORS[color_index])

    def new_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.current_tetromino.x = self.grid.width // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        if not self.grid.is_valid_move(self.current_tetromino):
            return False  # Game over
        return True

    def move_left(self):
        if self.current_tetromino:
            self.current_tetromino.x -= 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x += 1

    def move_right(self):
        if self.current_tetromino:
            self.current_tetromino.x += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x -= 1

    def move_down(self):
        if self.current_tetromino:
            self.current_tetromino.y += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.y -= 1
                self.lock_tetromino()
                return False # Tetromino locked
            return True # Tetromino moved down
        return False

    def rotate_tetromino(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.shape
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.shape = original_shape # Revert rotation

    def lock_tetromino(self):
        color_index = COLORS.index(self.current_tetromino.color)
        self.grid.place_tetromino(self.current_tetromino, color_index)
        lines_cleared = self.grid.clear_lines()
        if lines_cleared > 0:
            self.score += lines_cleared * lines_cleared * 100
            self.contribution += lines_cleared * lines_cleared * 100

    def draw(self, screen):
        self.grid.draw(screen, self.offset)
        if self.current_tetromino:
            for x, y in self.current_tetromino.get_cells():
                if y >= 0:
                    pygame.draw.rect(screen, self.current_tetromino.color, (self.offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, BLACK, (self.offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_next_tetromino(self, screen, x, y):
        if self.next_tetromino:
            for i in range(len(self.next_tetromino.shape)):
                for j in range(len(self.next_tetromino.shape[0])):
                    if self.next_tetromino.shape[i][j] == 1:
                        pygame.draw.rect(screen, self.next_tetromino.color, (x + j * CELL_SIZE, y + i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
