    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Collaborative Tetris")
    clock = pygame.time.Clock()

    player1 = Player(1, GRID_WIDTH, GRID_HEIGHT, 0)
    player2 = Player(2, GRID_WIDTH, GRID_HEIGHT, GRID_WIDTH * CELL_SIZE)
    player3 = Player(3, GRID_WIDTH, GRID_HEIGHT, 2 * GRID_WIDTH * CELL_SIZE)
    players = [player1, player2, player3]

    game_over = False
    fall_speed = 1  # Blocks fall one cell per fall_speed frames
    fall_counter = 0

    for player in players:
        if not player.new_tetromino():
            game_over = True
            break

    while not game_over:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                game_over = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    player1.move_left()
                if event.key == pygame.K_d:
                    player1.move_right()
                if event.key == pygame.K_q:
                    player1.rotate_tetromino()
                if event.key == pygame.K_j:
                    player2.move_left()
                if event.key == pygame.K_l:
                    player2.move_right()
                if event.key == pygame.K_u:
                    player2.rotate_tetromino()
                if event.key == pygame.K_LEFT:
                    player3.move_left()
                if event.key == pygame.K_RIGHT:
                    player3.move_right()
                if event.key == pygame.K_UP:
                    player3.rotate_tetromino()

        # Game Logic
        fall_counter += 1
        for player in players:
            if fall_counter % fall_speed == 0:
                if not player.move_down():
                    if not player.new_tetromino():
                        game_over = True
                        break

        # Drawing
        screen.fill(BLACK)
        for player in players:
            player.draw(screen)
            player.draw_next_tetromino(screen, player.offset + GRID_WIDTH * CELL_SIZE // 2 - CELL_SIZE * 2, HEIGHT - 5 * CELL_SIZE)
            font = pygame.font.Font(None, 30)
            text = font.render(f"Player {player.player_id}: {player.score}", True, WHITE)
            screen.blit(text, (player.offset, 10))

        pygame.display.flip()
        clock.tick(FPS)

    # Game Over Screen
    total_score = sum(player.score for player in players)
    contributions = [(player.player_id, player.contribution / total_score if total_score > 0 else 0) for player in players]

    while True:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                return

        screen.fill(BLACK)
        font = pygame.font.Font(None, 50)
        text = font.render("Game Over!", True, WHITE)
        text_rect = text.get_rect(center=(WIDTH // 2, HEIGHT // 4))
        screen.blit(text, text_rect)

        font = pygame.font.Font(None, 30)
        y_offset = HEIGHT // 2
        for player_id, contribution in contributions:
            text = font.render(f"Player {player_id}: {contribution:.2%}", True, WHITE)
            text_rect = text.get_rect(center=(WIDTH // 2, y_offset))
            screen.blit(text, text_rect)
            y_offset += 40

        pygame.display.flip()

if __name__ == "__main__":
