        if not self.game_over:
            self.frame_count += 1
            for player in self.players:
                if self.frame_count % self.drop_speed == 0:
                    if not player.move_tetromino_down():
                        if not player.spawn_tetromino():
                            self.game_over = True

    def render(self):
        self.screen.fill(BLACK)
        for i, player in enumerate(self.players):
            player.draw(self.screen, i * GRID_WIDTH * CELL_SIZE)
            score_text = self.font.render(f"Player {i+1}: {player.score}", True, WHITE)
