                if self.grid[y][x] != 0:
                    color = COLORS[self.grid[y][x] - 1]
                    pygame.draw.rect(screen, color, (offset_x + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
