class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [Player(i, GRID_WIDTH, GRID_HEIGHT) for i in range(3)]
        self.game_over = False
        self.font = pygame.font.Font(None, 36)
        self.frame_count = 0
        self.drop_speed = 30 # Frames between drops

        for player in self.players:
            if not player.spawn_tetromino():
                self.game_over = True

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:  # Player 0 - Left
                    self.players[0].move_tetromino_sideways(-1)
                if event.key == pygame.K_d:  # Player 0 - Right
                    self.players[0].move_tetromino_sideways(1)
                if event.key == pygame.K_s:  # Player 0 - Down
                    self.players[0].move_tetromino_down()
                if event.key == pygame.K_w:  # Player 0 - Rotate
                    self.players[0].rotate_tetromino()

                if event.key == pygame.K_j:  # Player 1 - Left
                    self.players[1].move_tetromino_sideways(-1)
                if event.key == pygame.K_l:  # Player 1 - Right
                    self.players[1].move_tetromino_sideways(1)
                if event.key == pygame.K_k:  # Player 1 - Down
                    self.players[1].move_tetromino_down()
                if event.key == pygame.K_i:  # Player 1 - Rotate
                    self.players[1].rotate_tetromino()

                if event.key == pygame.K_LEFT:  # Player 2 - Left
                    self.players[2].move_tetromino_sideways(-1)
                if event.key == pygame.K_RIGHT:  # Player 2 - Right
                    self.players[2].move_tetromino_sideways(1)
                if event.key == pygame.K_DOWN:  # Player 2 - Down
                    self.players[2].move_tetromino_down()
                if event.key == pygame.K_UP:  # Player 2 - Rotate
                    self.players[2].rotate_tetromino()

    def update(self):
        if not self.game_over:
            self.frame_count += 1
            for player in self.players:
                if self.frame_count % self.drop_speed == 0:
                    if not player.move_tetromino_down():
                        if not player.spawn_tetromino():
                            self.game_over = True

    def render(self):
        self.screen.fill(BLACK)
        for i, player in enumerate(self.players):
            player.draw(self.screen, i * GRID_WIDTH * CELL_SIZE)
            score_text = self.font.render(f"Player {i+1}: {player.score}", True, WHITE)
            self.screen.blit(score_text, (i * GRID_WIDTH * CELL_SIZE, HEIGHT - 30))

        if self.game_over:
            game_over_text = self.font.render("Game Over!", True, WHITE)
            self.screen.blit(game_over_text, (WIDTH // 2 - 80, HEIGHT // 2 - 18))

            total_score = sum(player.score for player in self.players)
            total_score_text = self.font.render(f"Total Score: {total_score}", True, WHITE)
            self.screen.blit(total_score_text, (WIDTH // 2 - 100, HEIGHT // 2 + 18))

            for i, player in enumerate(self.players):
                contribution_percentage = (player.contribution / total_score * 100) if total_score > 0 else 0
                contribution_text = self.font.render(f"Player {i+1} Contribution: {contribution_percentage:.2f}%", True, WHITE)
                self.screen.blit(contribution_text, (i * GRID_WIDTH * CELL_SIZE, HEIGHT - 60))

        pygame.display.flip()

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()
            self.render()
            self.clock.tick(FPS)
        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
WIDTH = GRID_WIDTH * CELL_SIZE * 3  # Three players side-by-side
HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
COLORS = [(0, 255, 255), (0, 0, 255), (255, 127, 0), (255, 255, 0), (0, 255, 0), (255, 0, 0), (128, 0, 128)]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 0], [1, 1, 1]]   # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])

        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j] == 1:
                    cells.append((self.x + j, self.y + i))
        return cells

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        for x, y in tetromino.get_cells():
            if x < 0 or x >= self.width or y >= self.height:
                return False
            if y >= 0 and self.grid[y][x] != 0:
                return False
        return True

    def place_tetromino(self, tetromino, color_index):
        for x, y in tetromino.get_cells():
            if y >= 0:
                self.grid[y][x] = color_index + 1 # +1 to avoid 0 (empty cell)

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen, offset):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x] != 0:
                    color = COLORS[self.grid[y][x] - 1]
                    pygame.draw.rect(screen, color, (offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, BLACK, (offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)
                else:
                    pygame.draw.rect(screen, WHITE, (offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, GRAY, (offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

class Player:
    def __init__(self, player_id, grid_width, grid_height, offset):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.score = 0
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.offset = offset
        self.contribution = 0 # Track player's contribution to the overall score

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color_index = random.randint(0, len(COLORS) - 1)
        return Tetromino(self.grid.width // 2 - len(shape[0]) // 2, 0, shape, COLORS[color_index])

    def new_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.current_tetromino.x = self.grid.width // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        if not self.grid.is_valid_move(self.current_tetromino):
            return False  # Game over
        return True

    def move_left(self):
        if self.current_tetromino:
            self.current_tetromino.x -= 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x += 1

    def move_right(self):
        if self.current_tetromino:
            self.current_tetromino.x += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x -= 1

    def move_down(self):
        if self.current_tetromino:
            self.current_tetromino.y += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.y -= 1
                self.lock_tetromino()
                return False # Tetromino locked
            return True # Tetromino moved down
        return False

    def rotate_tetromino(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.shape
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.shape = original_shape # Revert rotation

    def lock_tetromino(self):
        color_index = COLORS.index(self.current_tetromino.color)
        self.grid.place_tetromino(self.current_tetromino, color_index)
        lines_cleared = self.grid.clear_lines()
        if lines_cleared > 0:
            self.score += lines_cleared * lines_cleared * 100
            self.contribution += lines_cleared * lines_cleared * 100

    def draw(self, screen):
        self.grid.draw(screen, self.offset)
        if self.current_tetromino:
            for x, y in self.current_tetromino.get_cells():
                if y >= 0:
                    pygame.draw.rect(screen, self.current_tetromino.color, (self.offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, BLACK, (self.offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_next_tetromino(self, screen, x, y):
        if self.next_tetromino:
            for i in range(len(self.next_tetromino.shape)):
                for j in range(len(self.next_tetromino.shape[0])):
                    if self.next_tetromino.shape[i][j] == 1:
                        pygame.draw.rect(screen, self.next_tetromino.color, (x + j * CELL_SIZE, y + i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                        pygame.draw.rect(screen, BLACK, (x + j * CELL_SIZE, y + i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Collaborative Tetris")
    clock = pygame.time.Clock()

    player1 = Player(1, GRID_WIDTH, GRID_HEIGHT, 0)
    player2 = Player(2, GRID_WIDTH, GRID_HEIGHT, GRID_WIDTH * CELL_SIZE)
    player3 = Player(3, GRID_WIDTH, GRID_HEIGHT, 2 * GRID_WIDTH * CELL_SIZE)
    players = [player1, player2, player3]

    game_over = False
    fall_speed = 1  # Blocks fall one cell per fall_speed frames
    fall_counter = 0

    for player in players:
        if not player.new_tetromino():
            game_over = True
            break

    while not game_over:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                game_over = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    player1.move_left()
                if event.key == pygame.K_d:
                    player1.move_right()
                if event.key == pygame.K_q:
                    player1.rotate_tetromino()
                if event.key == pygame.K_j:
                    player2.move_left()
                if event.key == pygame.K_l:
                    player2.move_right()
                if event.key == pygame.K_u:
                    player2.rotate_tetromino()
                if event.key == pygame.K_LEFT:
                    player3.move_left()
                if event.key == pygame.K_RIGHT:
                    player3.move_right()
                if event.key == pygame.K_UP:
                    player3.rotate_tetromino()

        # Game Logic
        fall_counter += 1
        for player in players:
            if fall_counter % fall_speed == 0:
                if not player.move_down():
                    if not player.new_tetromino():
                        game_over = True
                        break

        # Drawing
        screen.fill(BLACK)
        for player in players:
            player.draw(screen)
            player.draw_next_tetromino(screen, player.offset + GRID_WIDTH * CELL_SIZE // 2 - CELL_SIZE * 2, HEIGHT - 5 * CELL_SIZE)
            font = pygame.font.Font(None, 30)
            text = font.render(f"Player {player.player_id}: {player.score}", True, WHITE)
            screen.blit(text, (player.offset, 10))

        pygame.display.flip()
        clock.tick(FPS)

    # Game Over Screen
    total_score = sum(player.score for player in players)
    contributions = [(player.player_id, player.contribution / total_score if total_score > 0 else 0) for player in players]

    while True:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                return

        screen.fill(BLACK)
        font = pygame.font.Font(None, 50)
        text = font.render("Game Over!", True, WHITE)
        text_rect = text.get_rect(center=(WIDTH // 2, HEIGHT // 4))
        screen.blit(text, text_rect)

        font = pygame.font.Font(None, 30)
        y_offset = HEIGHT // 2
        for player_id, contribution in contributions:
            text = font.render(f"Player {player_id}: {contribution:.2%}", True, WHITE)
            text_rect = text.get_rect(center=(WIDTH // 2, y_offset))
            screen.blit(text, text_rect)
            y_offset += 40

        pygame.display.flip()

if __name__ == "__main__":
    main()

