        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [Player(i, GRID_WIDTH, GRID_HEIGHT) for i in range(3)]
        self.game_over = False
        self.font = pygame.font.Font(None, 36)
        self.frame_count = 0
        self.drop_speed = 30 # Frames between drops

        for player in self.players:
            if not player.spawn_tetromino():
                self.game_over = True

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:  # Player 0 - Left
                    self.players[0].move_tetromino_sideways(-1)
                if event.key == pygame.K_d:  # Player 0 - Right
                    self.players[0].move_tetromino_sideways(1)
                if event.key == pygame.K_s:  # Player 0 - Down
                    self.players[0].move_tetromino_down()
                if event.key == pygame.K_w:  # Player 0 - Rotate
                    self.players[0].rotate_tetromino()

                if event.key == pygame.K_j:  # Player 1 - Left
                    self.players[1].move_tetromino_sideways(-1)
                if event.key == pygame.K_l:  # Player 1 - Right
                    self.players[1].move_tetromino_sideways(1)
                if event.key == pygame.K_k:  # Player 1 - Down
                    self.players[1].move_tetromino_down()
                if event.key == pygame.K_i:  # Player 1 - Rotate
                    self.players[1].rotate_tetromino()

                if event.key == pygame.K_LEFT:  # Player 2 - Left
                    self.players[2].move_tetromino_sideways(-1)
                if event.key == pygame.K_RIGHT:  # Player 2 - Right
                    self.players[2].move_tetromino_sideways(1)
                if event.key == pygame.K_DOWN:  # Player 2 - Down
                    self.players[2].move_tetromino_down()
                if event.key == pygame.K_UP:  # Player 2 - Rotate
                    self.players[2].rotate_tetromino()

    def update(self):
        if not self.game_over:
            self.frame_count += 1
            for player in self.players:
                if self.frame_count % self.drop_speed == 0:
                    if not player.move_tetromino_down():
                        if not player.spawn_tetromino():
                            self.game_over = True

    def render(self):
        self.screen.fill(BLACK)
        for i, player in enumerate(self.players):
            player.draw(self.screen, i * GRID_WIDTH * CELL_SIZE)
            score_text = self.font.render(f"Player {i+1}: {player.score}", True, WHITE)
            self.screen.blit(score_text, (i * GRID_WIDTH * CELL_SIZE, HEIGHT - 30))

        if self.game_over:
            game_over_text = self.font.render("Game Over!", True, WHITE)
            self.screen.blit(game_over_text, (WIDTH // 2 - 80, HEIGHT // 2 - 18))

            total_score = sum(player.score for player in self.players)
            total_score_text = self.font.render(f"Total Score: {total_score}", True, WHITE)
            self.screen.blit(total_score_text, (WIDTH // 2 - 100, HEIGHT // 2 + 18))

            for i, player in enumerate(self.players):
                contribution_percentage = (player.contribution / total_score * 100) if total_score > 0 else 0
                contribution_text = self.font.render(f"Player {i+1} Contribution: {contribution_percentage:.2f}%", True, WHITE)
                self.screen.blit(contribution_text, (i * GRID_WIDTH * CELL_SIZE, HEIGHT - 60))

        pygame.display.flip()

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()
            self.render()
            self.clock.tick(FPS)
        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

