                if event.key == pygame.K_i:
                    games[2].rotate_piece()
                if event.key == pygame.K_u:
                    games[2].hard_drop()

        # Game Logic
        for game in games:
            if not game.game_over:
                if fall_time / 1000 >= (1 / game.drop_speed):
                    game.move_down()
                    fall_time = 0

        # Drawing
        screen.fill(BLACK)
        for i, game in enumerate(games):
            game.draw(screen, i * GRID_WIDTH)

            if game.game_over:
                font = pygame.font.Font(None, 50)
                text = font.render(f"Player {i + 1} Game Over!", True, WHITE)
                text_rect = text.get_rect(center=( (i * GRID_WIDTH + GRID_WIDTH/2) * BLOCK_SIZE, SCREEN_HEIGHT/2))
                screen.blit(text, text_rect)

        pygame.display.flip()
        clock.tick(FPS)

    # Calculate and display contributions
    total_score = sum(game.score for game in games)
    if total_score > 0:
        print("Player Contributions:")
        for i, game in enumerate(games):
            contribution = (game.score / total_score) * 100
            print(f"Player {i + 1}: {contribution:.2f}%")
