GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
ORANGE = (255, 165, 0)

COLORS = [RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA, ORANGE]

# Tetromino shapes (rotations)
SHAPES = {
    "I": [[(0, 0), (1, 0), (2, 0), (3, 0)],
          [(0, 0), (0, 1), (0, 2), (0, 3)]],
    "J": [[(0, 0), (1, 0), (2, 0), (2, 1)],
          [(1, 0), (1, 1), (1, 2), (0, 2)],
          [(0, 0), (0, 1), (1, 1), (2, 1)],
          [(0, 0), (0, 1), (0, 2), (1, 0)]],
    "L": [[(0, 0), (1, 0), (2, 0), (0, 1)],
          [(0, 0), (0, 1), (0, 2), (1, 2)],
          [(2, 0), (0, 1), (1, 1), (2, 1)],
          [(0, 0), (1, 0), (1, 1), (1, 2)]],
    "O": [[(0, 0), (1, 0), (0, 1), (1, 1)]],
    "S": [[(1, 0), (2, 0), (0, 1), (1, 1)],
          [(0, 0), (0, 1), (1, 1), (1, 2)]],
    "T": [[(1, 0), (0, 1), (1, 1), (2, 1)],
          [(1, 0), (0, 1), (1, 1), (1, 2)],
