          [(0, 0), (0, 1), (1, 1), (0, 2)]],
    "Z": [[(0, 0), (1, 0), (1, 1), (2, 1)],
          [(1, 0), (0, 1), (1, 1), (0, 2)]]
}

class Piece:
    def __init__(self, x, y, shape):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = random.choice(COLORS)
        self.rotation = 0

    def get_shape(self):
        return SHAPES[self.shape][self.rotation % len(SHAPES[self.shape])]

    def rotate(self):
        self.rotation += 1

    def unrotate(self):
        self.rotation -= 1

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[BLACK for _ in range(width)] for _ in range(height)]

    def is_inside(self, x, y):
        return 0 <= x < self.width and 0 <= y < self.height

    def is_empty(self, x, y):
        return self.grid[y][x] == BLACK

    def is_valid_position(self, piece):
        for x, y in piece.get_shape():
            grid_x = piece.x + x
            grid_y = piece.y + y
            if not self.is_inside(grid_x, grid_y) or not self.is_empty(grid_x, grid_y):
                return False
        return True

    def place_piece(self, piece):
        for x, y in piece.get_shape():
            self.grid[piece.y + y][piece.x + x] = piece.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y][x] != BLACK for x in range(self.width)):
                lines_cleared += 1
                del self.grid[y]
                self.grid.insert(0, [BLACK for _ in range(self.width)])
        return lines_cleared

    def reset(self):
        self.grid = [[BLACK for _ in range(self.width)] for _ in range(self.height)]

class Player:
    def __init__(self, player_id, x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.x_offset = x_offset
        self.current_piece = None
        self.next_piece = self.new_piece()
        self.game_over = False

    def new_piece(self):
        shape = random.choice(list(SHAPES.keys()))
        return Piece(GRID_WIDTH // 2 - 2, 0, shape)

    def spawn_piece(self):
        self.current_piece = self.next_piece
        self.next_piece = self.new_piece()
        if not self.grid.is_valid_position(self.current_piece):
            self.game_over = True

    def move_piece_down(self):
        if self.game_over:
            return

        self.current_piece.y += 1
        if not self.grid.is_valid_position(self.current_piece):
            self.current_piece.y -= 1
            self.grid.place_piece(self.current_piece)
            lines_cleared = self.grid.clear_lines()
            self.score += lines_cleared ** 2 * 100  # Example scoring
            self.spawn_piece()

    def move_piece_sideways(self, direction):
        if self.game_over:
            return

        self.current_piece.x += direction
        if not self.grid.is_valid_position(self.current_piece):
            self.current_piece.x -= direction

    def rotate_piece(self):
        if self.game_over:
            return

        self.current_piece.rotate()
        if not self.grid.is_valid_position(self.current_piece):
            self.current_piece.unrotate()

    def drop_piece(self):
        if self.game_over:
            return

        while self.grid.is_valid_position(self.current_piece):
            self.current_piece.y += 1
        self.current_piece.y -= 1
        self.grid.place_piece(self.current_piece)
        lines_cleared = self.grid.clear_lines()
        self.score += lines_cleared ** 2 * 100
        self.spawn_piece()

    def reset(self):
        self.grid.reset()
        self.score = 0
        self.game_over = False
        self.current_piece = None
        self.next_piece = self.new_piece()
        self.spawn_piece()

def draw_grid(screen, grid, x_offset):
    for y in range(grid.height):
        for x in range(grid.width):
            pygame.draw.rect(screen, grid.grid[y][x],
                             (x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 0)
            pygame.draw.rect(screen, GRAY,
                             (x_offset + x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

def draw_piece(screen, piece, x_offset):
