import random

class Player:
    def __init__(self, name, location):
        self.name = name
        self.location = location
        self.score = 0
        self.contributions = {}  # Store contributions to overall score

    def add_score(self, points, reason=""):
        self.score += points
        if reason:
            if reason not in self.contributions:
                self.contributions[reason] = 0
            self.contributions[reason] += points

    def get_contribution_percentage(self, reason, total_score):
        if total_score == 0:
            return 0
        if reason in self.contributions:
            return (self.contributions[reason] / total_score) * 100
        else:
            return 0

    def __repr__(self):
        return f"Player(name='{self.name}', location='{self.location}', score={self.score})"


class Game:
    def __init__(self, players):
        self.players = players
        self.total_score = 0

    def add_to_total_score(self, points):
        self.total_score += points

    def determine_winner(self):
        if not self.players:
            return None

        winner = max(self.players, key=lambda player: player.score)
        return winner

    def display_scores(self):
        print("--- Game Scores ---")
        for player in self.players:
            print(f"{player.name}: {player.score}")
        print(f"Total Score: {self.total_score}")

    def display_contributions(self):
        print("\n--- Player Contributions ---")
        for player in self.players:
            print(f"\n{player.name}:")
            for reason, points in player.contributions.items():
                percentage = player.get_contribution_percentage(reason, self.total_score)
                print(f"  - {reason}: {points} points ({percentage:.2f}%)")

    def simulate_round(self):
        # Simulate a round where players earn points
        for player in self.players:
            points = random.randint(10, 50)
            reason = random.choice(["Resource Gathering", "Combat", "Exploration"])
            player.add_score(points, reason)
            self.add_to_total_score(points)
        print("Round Simulated!")


