import random

class Player:
    def __init__(self, name, location):
        self.name = name
        self.location = location
        self.score = 0
        self.contributions = {}  # Store contributions to each round

    def add_score(self, round_number, score):
        self.score += score
        self.contributions[round_number] = score

    def get_contribution(self, round_number):
        return self.contributions.get(round_number, 0)

    def __repr__(self):
        return f"Player(name='{self.name}', location='{self.location}', score={self.score})"


class Game:
    def __init__(self, players):
        self.players = players
        self.round_number = 0
        self.round_results = {} # Store results of each round

    def start_round(self):
        self.round_number += 1
        print(f"\n--- Round {self.round_number} ---")
        self.round_results[self.round_number] = {}

    def play_round(self):
        if not self.round_number:
            print("Start a round first using start_round()")
            return

        for player in self.players:
            # Simulate player action and score generation
            score = random.randint(10, 50)  # Example score range
            print(f"{player.name} scored {score} in Round {self.round_number}")
            player.add_score(self.round_number, score)
            self.round_results[self.round_number][player.name] = score

    def end_round(self):
        if not self.round_number:
            print("No round in progress.")
            return

        print(f"\n--- Round {self.round_number} Results ---")
        for player in self.players:
            print(f"{player.name}: Score = {player.score}, Round Contribution = {player.get_contribution(self.round_number)}")

    def determine_fair_contributions(self):
        """
        Determines the contribution of each player to the overall score in a fair manner.
        This example uses a simple proportional contribution based on round scores.
        More sophisticated methods could be implemented here.
        """
        print("\n--- Fair Contribution Analysis ---")
        for round_num in self.round_results:
            total_round_score = sum(self.round_results[round_num].values())
            print(f"\nRound {round_num}: Total Score = {total_round_score}")
            for player in self.players:
                player_score = self.round_results[round_num].get(player.name, 0)
                if total_round_score > 0:
                    contribution_percentage = (player_score / total_round_score) * 100
                else:
                    contribution_percentage = 0
                print(f"{player.name}: Contribution = {player_score}, Percentage = {contribution_percentage:.2f}%")

    def display_leaderboard(self):
        print("\n--- Leaderboard ---")
        sorted_players = sorted(self.players, key=lambda player: player.score, reverse=True)
        for player in sorted_players:
            print(f"{player.name}: {player.score}")


