import random

class Player:
    def __init__(self, player_id, name):
        self.player_id = player_id
        self.name = name
        self.score = 0
        self.contributions = {}  # Store contributions to different scores

    def add_contribution(self, score_type, amount):
        if score_type not in self.contributions:
            self.contributions[score_type] = 0
        self.contributions[score_type] += amount

    def get_contribution(self, score_type):
        return self.contributions.get(score_type, 0)

    def update_score(self, score_increase):
        self.score += score_increase

    def get_score(self):
        return self.score

    def __repr__(self):
        return f"Player(ID: {self.player_id}, Name: {self.name}, Score: {self.score})"


class Game:
    def __init__(self, game_id, game_name):
        self.game_id = game_id
        self.game_name = game_name
        self.players = []
        self.scores = {}  # Store different score types and their values

    def add_player(self, player):
        self.players.append(player)

    def remove_player(self, player_id):
        self.players = [p for p in self.players if p.player_id != player_id]

    def add_score_type(self, score_type, initial_value=0):
        self.scores[score_type] = initial_value

    def update_score(self, score_type, value_change):
        if score_type in self.scores:
            self.scores[score_type] += value_change
        else:
            print(f"Error: Score type '{score_type}' not found.")

    def get_score(self, score_type):
        return self.scores.get(score_type, None)

    def distribute_score(self, score_type, contributing_players, amount):
        """Distributes a score among contributing players fairly."""
        num_players = len(contributing_players)
        if num_players == 0:
            return

        base_amount = amount // num_players
        remainder = amount % num_players

        for player in contributing_players:
            player.add_contribution(score_type, base_amount)
            player.update_score(base_amount)

        # Distribute the remainder randomly
        for i in range(remainder):
            player_index = i % num_players
            player = contributing_players[player_index]
            player.add_contribution(score_type, 1)
            player.update_score(1)

    def get_player_contributions(self, player_id):
        player = next((p for p in self.players if p.player_id == player_id), None)
        if player:
            return player.contributions
        else:
            return None

    def calculate_fair_contribution(self, player_id, score_type):
        """Calculates a player's fair contribution to a specific score type."""
        player = next((p for p in self.players if p.player_id == player_id), None)
        if not player:
            return 0

        total_score = self.get_score(score_type)
        if total_score == 0:
            return 0

        total_contributions = sum(p.get_contribution(score_type) for p in self.players)
        if total_contributions == 0:
            return 0

        player_contribution = player.get_contribution(score_type)
        return (player_contribution / total_contributions) * total_score

    def display_leaderboard(self):
        sorted_players = sorted(self.players, key=lambda p: p.score, reverse=True)
        print(f"Leaderboard for {self.game_name}:")
        for player in sorted_players:
            print(f"{player.name}: {player.score}")

    def __repr__(self):
        return f"Game(ID: {self.game_id}, Name: {self.game_name}, Players: {self.players})"


