class Task:
    def __init__(self, task_id, description, points_possible):
        self.task_id = task_id
        self.description = description
        self.points_possible = points_possible

    def __repr__(self):
        return f"Task(id={self.task_id}, description='{self.description}', points={self.points_possible})"


class Game:
    def __init__(self):
        self.players = []
        self.tasks = []
        self.scores = {}  # Store overall scores
        self.task_assignments = {} # Store task assignments to players

    def add_player(self, player):
        if player.player_id not in [p.player_id for p in self.players]:
            self.players.append(player)
            self.scores[player.player_id] = 0
        else:
            print(f"Player with ID {player.player_id} already exists.")

    def add_task(self, task):
        if task.task_id not in [t.task_id for t in self.tasks]:
            self.tasks.append(task)
        else:
            print(f"Task with ID {task.task_id} already exists.")

    def assign_task(self, player_id, task_id):
        if player_id not in self.scores:
            print(f"Player with ID {player_id} does not exist.")
            return
        if task_id not in [t.task_id for t in self.tasks]:
            print(f"Task with ID {task_id} does not exist.")
            return

        if task_id not in self.task_assignments:
            self.task_assignments[task_id] = []

        if player_id not in self.task_assignments[task_id]:
            self.task_assignments[task_id].append(player_id)
        else:
            print(f"Player {player_id} is already assigned to task {task_id}")

    def record_contribution(self, player_id, task_id, points):
        if player_id not in self.scores:
            print(f"Player with ID {player_id} does not exist.")
            return
        if task_id not in [t.task_id for t in self.tasks]:
            print(f"Task with ID {task_id} does not exist.")
            return

        player = next((p for p in self.players if p.player_id == player_id), None)
        task = next((t for t in self.tasks if t.task_id == task_id), None)

        if player and task:
            if points > task.points_possible:
                print(f"Points awarded ({points}) exceeds maximum points possible for task {task_id} ({task.points_possible}).")
                points = task.points_possible

            player.add_contribution(task_id, points)
            self.scores[player_id] += points
        else:
            print("Player or task not found.")

    def get_player_score(self, player_id):
        if player_id in self.scores:
            return self.scores[player_id]
        else:
            print(f"Player with ID {player_id} does not exist.")
            return None

    def get_task_assignments(self, task_id):
        if task_id in self.task_assignments:
            return self.task_assignments[task_id]
        else:
            return []

    def calculate_fair_contributions(self):
        """Calculates and prints the contribution of each player to the overall score."""
        total_score = sum(self.scores.values())
        if total_score == 0:
            print("No contributions recorded yet.")
            return

        print("Fair Contribution Analysis:")
        for player in self.players:
            player_score = self.get_player_score(player.player_id)
            if player_score is not None:
                percentage = (player_score / total_score) * 100
                print(f"Player {player.name} (ID: {player.player_id}): Score = {player_score}, Contribution = {percentage:.2f}%")

    def generate_leaderboard(self):
        """Generates and prints a leaderboard based on player scores."""
        sorted_players = sorted(self.players, key=lambda player: self.scores[player.player_id], reverse=True)
        print("\nLeaderboard:")
        for i, player in enumerate(sorted_players):
            print(f"{i+1}. {player.name} (ID: {player.player_id}): Score = {self.scores[player.player_id]}")

    def simulate_game(self, num_players=3, num_tasks=5, num_rounds=10):
        """Simulates a game with random player contributions."""
        # Create players
        for i in range(num_players):
            self.add_player(Player(i + 1, f"Player {i + 1}"))

        # Create tasks
        for i in range(num_tasks):
            self.add_task(Task(i + 1, f"Task {i + 1}", random.randint(10, 50)))

        # Simulate rounds
        for _ in range(num_rounds):
            player_id = random.choice(list(self.scores.keys()))
            task_id = random.choice([t.task_id for t in self.tasks])
            points = random.randint(0, next(t for t in self.tasks if t.task_id == task_id).points_possible)
            self.record_contribution(player_id, task_id, points)

        self.calculate_fair_contributions()
        self.generate_leaderboard()


if __name__ == '__main__':
    game = Game()
    game.simulate_game()

