            self.snake_positions.append([(self.grid_size // 2, self.grid_size // 2)])  # Initial snake position
            self.snake_directions.append(random.choice(['up', 'down', 'left', 'right']))  # Initial direction
            self.scores.append(0)
            self.food_positions.append(self.generate_food_position())

    def generate_food_position(self):
        while True:
            food_x = random.randint(0, self.grid_size - 1)
            food_y = random.randint(0, self.grid_size - 1)
            food_position = (food_x, food_y)

            # Check if food spawns on any snake
            valid_position = True
            for snake in self.snake_positions:
                if food_position in snake:
                    valid_position = False
                    break

            if valid_position:
                return food_position

    def update_game_state(self):
        if self.game_over:
            return

        for player_index in range(self.num_players):
            self.move_snake(player_index)
            self.check_collision(player_index)
            self.check_food_consumption(player_index)

    def move_snake(self, player_index):
        head_x, head_y = self.snake_positions[player_index][0]
        direction = self.snake_directions[player_index]

        if direction == 'up':
            new_head = (head_x, (head_y - 1) % self.grid_size)
        elif direction == 'down':
            new_head = (head_x, (head_y + 1) % self.grid_size)
        elif direction == 'left':
            new_head = ((head_x - 1) % self.grid_size, head_y)
        elif direction == 'right':
            new_head = ((head_x + 1) % self.grid_size, head_y)

        self.snake_positions[player_index].insert(0, new_head)
        self.snake_positions[player_index].pop()  # Remove tail

    def check_collision(self, player_index):
        head_x, head_y = self.snake_positions[player_index][0]

        # Collision with self
        if (head_x, head_y) in self.snake_positions[player_index][1:]:
            self.game_over = True
            return

        # Collision with other snakes
        for i in range(self.num_players):
            if i != player_index and (head_x, head_y) in self.snake_positions[i]:
                self.game_over = True
                return

    def check_food_consumption(self, player_index):
        head_x, head_y = self.snake_positions[player_index][0]
        if (head_x, head_y) == self.food_positions[player_index]:
            self.scores[player_index] += 1
            self.snake_positions[player_index].insert(0, (head_x, head_y))  # Grow snake
            self.food_positions[player_index] = self.generate_food_position()

    def change_direction(self, player_index, new_direction):
        current_direction = self.snake_directions[player_index]
        if (new_direction == 'up' and current_direction != 'down') or \
           (new_direction == 'down' and current_direction != 'up') or \
           (new_direction == 'left' and current_direction != 'right') or \
           (new_direction == 'right' and current_direction != 'left'):
            self.snake_directions[player_index] = new_direction

    def get_game_state(self):
        return {
            'snake_positions': self.snake_positions,
            'food_positions': self.food_positions,
            'scores': self.scores,
            'game_over': self.game_over,
            'grid_size': self.grid_size
        }

