    def initialize_game(self):
        self.snake_positions = []
        self.food_positions = []
        self.snake_directions = []
        self.scores = []
        self.game_over = False

        for i in range(self.num_players):
            start_x = random.randint(3, self.grid_size - 4)
            start_y = random.randint(3, self.grid_size - 4)
            self.snake_positions.append([(start_x, start_y)])
            self.snake_directions.append(random.choice(['up', 'down', 'left', 'right']))
            self.scores.append(0)
            self.food_positions.append(self.generate_food())

    def generate_food(self):
        while True:
            food_x = random.randint(0, self.grid_size - 1)
            food_y = random.randint(0, self.grid_size - 1)
            valid = True
            for snake in self.snake_positions:
                if (food_x, food_y) in snake:
                    valid = False
                    break
            if valid:
                return (food_x, food_y)

    def update_game_state(self):
        if self.game_over:
            return

        for player_index in range(self.num_players):
            self.move_snake(player_index)
            if self.check_collision(player_index):
                self.game_over = True
                return
            if self.check_food_collision(player_index):
                self.eat_food(player_index)
            else:
                self.snake_positions[player_index] = self.snake_positions[player_index][1:]  # Remove tail

    def move_snake(self, player_index):
        head_x, head_y = self.snake_positions[player_index][0]
        direction = self.snake_directions[player_index]

        if direction == 'up':
            new_head = (head_x, head_y - 1)
        elif direction == 'down':
            new_head = (head_x, head_y + 1)
        elif direction == 'left':
            new_head = (head_x - 1, head_y)
        elif direction == 'right':
            new_head = (head_x + 1, head_y)

        self.snake_positions[player_index].insert(0, new_head)

    def check_collision(self, player_index):
        head_x, head_y = self.snake_positions[player_index][0]

        if head_x < 0 or head_x >= self.grid_size or head_y < 0 or head_y >= self.grid_size:
            return True

        for i in range(1, len(self.snake_positions[player_index])):
            if self.snake_positions[player_index][i] == (head_x, head_y):
                return True

        for other_player_index in range(self.num_players):
            if other_player_index != player_index:
                if (head_x, head_y) in self.snake_positions[other_player_index]:
                    return True

        return False

    def check_food_collision(self, player_index):
        head_x, head_y = self.snake_positions[player_index][0]
        food_x, food_y = self.food_positions[player_index]
        return (head_x, head_y) == (food_x, food_y)

    def eat_food(self, player_index):
        self.scores[player_index] += 1
        self.food_positions[player_index] = self.generate_food()

    def change_direction(self, player_index, new_direction):
        current_direction = self.snake_directions[player_index]
        if (new_direction == 'up' and current_direction != 'down') or \
           (new_direction == 'down' and current_direction != 'up') or \
           (new_direction == 'left' and current_direction != 'right') or \
           (new_direction == 'right' and current_direction != 'left'):
            self.snake_directions[player_index] = new_direction

    def get_game_state(self):
        return {
            'snake_positions': self.snake_positions,
            'food_positions': self.food_positions,
            'scores': self.scores,
            'game_over': self.game_over,
            'grid_size': self.grid_size
        }

    def render(self):
        grid = [[' ' for _ in range(self.grid_size)] for _ in range(self.grid_size)]

        for player_index in range(self.num_players):
            for x, y in self.snake_positions[player_index]:
                grid[y][x] = str(player_index + 1)  # Use player number to represent snake

            food_x, food_y = self.food_positions[player_index]
            grid[food_y][food_x] = 'F'

        output = ""
        for row in grid:
            output += ''.join(row) + '\n'

        output += "Scores: "
        for i in range(self.num_players):
            output += f"Player {i+1}: {self.scores[i]}  "

        if self.game_over:
            output += "\nGame Over!"

        return output

