class Team:
    def __init__(self, name):
        self.name = name
        self.players = []

    def add_player(self, player):
        if isinstance(player, Player):
            self.players.append(player)
        else:
            raise ValueError("Invalid player object. Must be an instance of Player class.")

    def remove_player(self, player_name):
        self.players = [player for player in self.players if player.name != player_name]

    def update_contribution(self, player_name, contribution_amount):
        for player in self.players:
            if player.name == player_name:
                player.contribution += contribution_amount
                return
        raise ValueError(f"Player with name '{player_name}' not found in the team.")

    def get_player(self, player_name):
        for player in self.players:
            if player.name == player_name:
                return player
        return None

    def display_team_summary(self):
        print(f"Team Name: {self.name}")
        if not self.players:
            print("No players in the team.")
            return

        print("Players:")
        for player in self.players:
            print(f"  - Name: {player.name}, Role: {player.role}, Contribution: {player.contribution}")

    def calculate_total_contribution(self):
        total_contribution = sum(player.contribution for player in self.players)
        return total_contribution


